import React, { useEffect, useState } from "react";
import database from "./firebase";
import { ref, onValue, set } from "firebase/database";
import { LineChart, Line, XAxis, YAxis, Tooltip, CartesianGrid } from "recharts";

function App() {
  const [leftFootData, setLeftFootData] = useState([]);

  const handleStart = () => {
    set(ref(database, "commands/recording"), true);
  };

  const handleStop = () => {
    set(ref(database, "commands/recording"), false);
  };

  useEffect(() => {
    const leftFootRef = ref(database, "leftFoot");
    onValue(leftFootRef, (snapshot) => {
      const data = snapshot.val();
      if (data) {
        const formatted = Object.entries(data).map(([ts, values]) => {
          const ax = values.accel_x || 0;
          const ay = values.accel_y || 0;
          const az = values.accel_z || 0;
          const magnitude = Math.sqrt(ax**2 + ay**2 + az**2);
          return { timestamp: ts, accel: magnitude };
        });
        setLeftFootData(formatted);
      }
    });
  }, []);

  return (
    <div>
      <h2>Left Foot Acceleration vs Timestamp</h2>
      <LineChart width={600} height={300} data={leftFootData}>
        <CartesianGrid stroke="#ccc" />
        <XAxis dataKey="timestamp" />
        <YAxis />
        <Tooltip />
        <Line type="monotone" dataKey="accel" stroke="#8884d8" />
      </LineChart>
      <button onClick={handleStart}>Start Recording</button>
      <button onClick={handleStop}>Stop Recording</button>
    </div>
  );
}

export default App;
